 namespace Pmpr\Common\Foundation\Data; class Meta extends Data { protected ?string $name = ''; protected ?string $title = ''; protected ?string $value = ''; protected ?string $icon = ''; protected ?int $priority = 1; public function getName() : ?string { return $this->name; } public function setName(?string $GCZRU) : self { $this->name = $GCZRU; return $this; } public function getTitle() : ?string { return $this->title; } public function setTitle(?string $aeybl) : self { $this->title = $aeybl; return $this; } public function getValue() : ?string { return $this->value; } public function setValue(?string $enUps) : self { $this->value = $enUps; return $this; } public function getIcon() : ?string { return $this->icon; } public function setIcon(?string $sHiS7) : self { $this->icon = $sHiS7; return $this; } public function getPriority() : ?int { return $this->priority; } public function setPriority(?int $m_Hjo) : self { $this->priority = $m_Hjo; return $this; } }
